import random
from datetime import date

def get_daily_horoscope(birth_date):
    today = date.today()
    # ใช้ "วันเกิด + วันนี้" เป็น Seed เพื่อให้ดวงเปลี่ยนทุกวัน
    seed_str = f"{birth_date.strftime('%Y%m%d')}-{today.strftime('%Y%m%d')}"
    random.seed(seed_str)

    # รายการคำทำนาย (รวบรวมให้ใหม่ 110 ข้อความ ครอบคลุมทุกด้าน)
